mapper.select:
SELECT id, business_domain_id, code, name, preset
FROM domain_role
WHERE id = #{id}
  AND business_domain_id = #{domainId}
LIMIT 1

SELECT id
FROM domain_role
WHERE business_domain_id = #{domainId}
  AND code = #{code}
ORDER BY id DESC
LIMIT 1

mapper.insert:
INSERT INTO domain_role (
    business_domain_id, code, name, preset, created_at, updated_at
)
SELECT #{domainId}, #{code}, #{name}, 1, CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1
    FROM domain_role
    WHERE business_domain_id = #{domainId}
      AND code = #{code}
)

mapper.update:
UPDATE domain_role
SET code = #{code},
    name = #{name},
    updated_at = CURRENT_TIMESTAMP(3)
WHERE id = #{id}
  AND business_domain_id = #{domainId}

mapper.select:
SELECT COUNT(*)
FROM domain_member_role dmr
JOIN domain_member dm ON dm.id = dmr.domain_member_id
WHERE dmr.domain_role_id = #{roleId}
  AND dm.business_domain_id = #{domainId}
  AND dm.deleted_at IS NULL

mapper.delete:
DELETE FROM domain_role
WHERE id = #{id}
  AND business_domain_id = #{domainId}
